@Component({
  selector: 'doc-progress-item-list',
  template: DEFAULT_LIST_WRAPPER_COMPONENT_CONFIGURATION_TEMPLATE,
  imports: [DbxListWrapperComponentImportsModule],
  host: {
    class: 'dbx-list-no-hover-effects'
  },
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true
})
export class DocProgressItemListComponent extends AbstractDbxSelectionListWrapperDirective<ProgressItemValue> {
  constructor() {
    super({
      componentClass: DocProgressItemListViewComponent,
      defaultSelectionMode: 'view'
    });
  }
}

@Component({
  selector: 'doc-progress-item-list-view',
  template: DEFAULT_DBX_SELECTION_VALUE_LIST_COMPONENT_CONFIGURATION_TEMPLATE,
  imports: [DbxSelectionValueListViewComponentImportsModule],
  providers: provideDbxListView(DocProgressItemListViewComponent),
  host: {
    class: 'dbx-list-item-p0'
  },
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true
})
export class DocProgressItemListViewComponent extends AbstractDbxSelectionListViewDirective<ProgressItemValue> {
  readonly config: DbxSelectionValueListViewConfig<ProgressItemValueWithSelection> = {
    componentClass: DocProgressItemListViewItemComponent,
    mapValuesToItemValues: (values) => of(values.map((value) => ({ ...value, itemValue: value, icon: undefined })))
  };
}

@Component({
  selector: 'doc-progress-item-list-view-item',
  template: `
    <div class="dbx-list-item-padded-thick dbx-list-item-card dbx-list-two-line-item dbx-list-two-line-item-with-icon doc-progress-item">
      <div class="item-icon dbx-icon-tile" [dbxColor]="'primary'" [dbxColorTone]="18">
        <mat-icon>{{ icon }}</mat-icon>
      </div>
      <div class="item-left">
        <span class="doc-progress-item-title">{{ title }}</span>
        <span class="item-details">{{ progress }} of {{ total }} complete</span>
        <mat-progress-bar class="doc-progress-item-bar" mode="determinate" [value]="progressPercent"></mat-progress-bar>
      </div>
      <div class="item-right">
        <button mat-flat-button>View requirements</button>
      </div>
    </div>
  `,
  styles: [
    `
      .doc-progress-item-title {
        font-size: 1em;
        font-weight: 600;
      }

      .doc-progress-item-bar {
        margin-top: 6px;
      }
    `
  ],
  imports: [MatIconModule, MatButtonModule, MatProgressBar, DbxColorDirective],
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true
})
export class DocProgressItemListViewItemComponent extends AbstractDbxValueListViewItemComponent<ProgressItemValue> {
  get icon(): string {
    return this.itemValue.icon;
  }

  get title(): string {
    return this.itemValue.title;
  }

  get progress(): number {
    return this.itemValue.progress;
  }

  get total(): number {
    return this.itemValue.total;
  }

  get progressPercent(): number {
    return this.total > 0 ? Math.min(100, Math.round((this.progress / this.total) * 100)) : 0;
  }
}

export interface ProgressItemValue {
  readonly key: string;
  readonly title: string;
  readonly progress: number;
  readonly total: number;
  readonly icon: string;
}

@Component({
  selector: 'doc-two-line-item-list',
  template: DEFAULT_LIST_WRAPPER_COMPONENT_CONFIGURATION_TEMPLATE,
  imports: [DbxListWrapperComponentImportsModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true
})
export class DocTwoLineItemListComponent extends AbstractDbxSelectionListWrapperDirective<TwoLineItemValue> {
  constructor() {
    super({
      componentClass: DocTwoLineItemListViewComponent,
      defaultSelectionMode: 'view'
    });
  }
}

@Component({
  selector: 'doc-two-line-item-list-view',
  template: DEFAULT_DBX_SELECTION_VALUE_LIST_COMPONENT_CONFIGURATION_TEMPLATE,
  imports: [DbxSelectionValueListViewComponentImportsModule],
  providers: provideDbxListView(DocTwoLineItemListViewComponent),
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true
})
export class DocTwoLineItemListViewComponent extends AbstractDbxSelectionListViewDirective<TwoLineItemValue> {
  readonly config: DbxSelectionValueListViewConfig<TwoLineItemValueWithSelection> = {
    componentClass: DocTwoLineItemListViewItemComponent,
    mapValuesToItemValues: (values) => of(values.map((value) => ({ ...value, itemValue: value, icon: value.icon })))
  };
}

@Component({
  selector: 'doc-two-line-item-list-view-item',
  template: `
    <div class="dbx-list-item-padded dbx-list-two-line-item">
      <div class="item-left">
        <span class="item-title">{{ title }}</span>
        @if (details) {
          <span class="item-details">{{ details }}</span>
        }
        @if (footnote) {
          <span class="item-details-footnote">{{ footnote }}</span>
        }
      </div>
      <dbx-spacer></dbx-spacer>
      <div class="item-right">
        @if (status) {
          <dbx-chip [small]="true" [color]="statusColor">{{ status }}</dbx-chip>
        }
      </div>
    </div>
  `,
  imports: [DbxSpacerDirective, DbxChipDirective],
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true
})
export class DocTwoLineItemListViewItemComponent extends AbstractDbxValueListViewItemComponent<TwoLineItemValue> {
  get title(): string {
    return this.itemValue.title;
  }

  get details(): Maybe<string> {
    return this.itemValue.details;
  }

  get footnote(): Maybe<string> {
    return this.itemValue.footnote;
  }

  get status(): Maybe<TwoLineItemValue['status']> {
    return this.itemValue.status;
  }

  get statusColor(): TwoLineItemStatusColor {
    return this.status ? STATUS_COLOR[this.status] : 'grey';
  }
}

export interface TwoLineItemValue {
  readonly key: string;
  readonly icon?: Maybe<string>;
  readonly title: string;
  readonly details?: Maybe<string>;
  readonly footnote?: Maybe<string>;
  readonly status?: Maybe<'active' | 'pending' | 'archived'>;
}
